// SAT R&W Batch 5 - Grammar & Writing II (120 questions)
export const rwBatch5 = [
  { id: 'sat_rw_b5_001', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The group of students ________ excited about the upcoming field trip.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were being' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Group" is a singular collective noun, so "is" is correct.' },
  { id: 'sat_rw_b5_002', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The recipe calls for three ingredients________ flour, sugar, and butter.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces a list after a complete sentence.' },
  { id: 'sat_rw_b5_003', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Every one of the books on the shelf ________ been read at least once.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'has' }, { letter: 'B', text: 'have' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'were' }], correct: 'A', explanation: '"Every one" is singular, requiring "has."' },
  { id: 'sat_rw_b5_004', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The cat cleaned ________ fur after eating dinner.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: "it's" }, { letter: 'C', text: 'their' }, { letter: 'D', text: "they're" }], correct: 'A', explanation: '"Its" is the possessive form. "It\'s" means "it is."' },
  { id: 'sat_rw_b5_005', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The park was beautiful. It had tall trees and a sparkling lake.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The beautiful park had tall trees and a sparkling lake.' }, { letter: 'B', text: 'The park was beautiful, it had tall trees and a lake.' }, { letter: 'C', text: 'Beautiful, the park had trees that were tall and a lake.' }, { letter: 'D', text: 'The park was beautiful and it had tall trees and it had a sparkling lake.' }], correct: 'A', explanation: 'Option A concisely combines both ideas without redundancy.' },
  { id: 'sat_rw_b5_006', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The children played ________ in the yard until it got dark.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'happily' }, { letter: 'B', text: 'happy' }, { letter: 'C', text: 'happier' }, { letter: 'D', text: 'happiness' }], correct: 'A', explanation: 'An adverb (happily) is needed to modify the verb "played."' },
  { id: 'sat_rw_b5_007', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'My sister who lives in Boston is a doctor.', question: 'If the speaker has only one sister, what punctuation is needed?', options: [{ letter: 'A', text: 'Commas around "who lives in Boston"' }, { letter: 'B', text: 'No commas needed' }, { letter: 'C', text: 'A semicolon before "who"' }, { letter: 'D', text: 'A dash before "who"' }], correct: 'A', explanation: 'With only one sister, "who lives in Boston" is nonessential information and needs commas.' },
  { id: 'sat_rw_b5_008', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'She runs ________ than her brother.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'faster' }, { letter: 'B', text: 'fastest' }, { letter: 'C', text: 'more fast' }, { letter: 'D', text: 'most fast' }], correct: 'A', explanation: 'Comparative form "faster" is used when comparing two people.' },
  { id: 'sat_rw_b5_009', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'Walking through the forest, ________.', question: 'Which choice correctly completes the sentence?', options: [{ letter: 'A', text: 'the hikers spotted a deer' }, { letter: 'B', text: 'a deer was spotted' }, { letter: 'C', text: 'the trees were tall' }, { letter: 'D', text: 'it was peaceful' }], correct: 'A', explanation: 'The participial phrase "Walking through the forest" must modify the subject doing the walking—"the hikers."' },
  { id: 'sat_rw_b5_010', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The teacher told the students to bring ________ textbooks to class.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'their' }, { letter: 'B', text: "they're" }, { letter: 'C', text: 'there' }, { letter: 'D', text: "there's" }], correct: 'A', explanation: '"Their" is the possessive pronoun referring to students.' },
  { id: 'sat_rw_b5_011', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The store sells many items________ clothing, electronics, and groceries are the most popular categories.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ';' }, { letter: 'B', text: ',' }, { letter: 'C', text: ':' }, { letter: 'D', text: '.' }], correct: 'A', explanation: 'A semicolon correctly joins two independent clauses.' },
  { id: 'sat_rw_b5_012', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The news about the layoffs ________ many employees by surprise.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'took' }, { letter: 'B', text: 'take' }, { letter: 'C', text: 'takes' }, { letter: 'D', text: 'taking' }], correct: 'A', explanation: '"News" is singular. In past tense: "The news took many employees by surprise."' },
  { id: 'sat_rw_b5_013', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Between you and ________, I think the project needs more time.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'me' }, { letter: 'B', text: 'I' }, { letter: 'C', text: 'myself' }, { letter: 'D', text: 'mine' }], correct: 'A', explanation: 'After a preposition ("between"), the objective form "me" is correct.' },
  { id: 'sat_rw_b5_014', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The movie was boring. I fell asleep halfway through.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The movie was so boring that I fell asleep halfway through.' }, { letter: 'B', text: 'The movie was boring, I fell asleep halfway through.' }, { letter: 'C', text: 'Boring, the movie made me fall asleep.' }, { letter: 'D', text: 'The movie was boring and falling asleep.' }], correct: 'A', explanation: '"So boring that" establishes the cause-effect relationship clearly.' },
  { id: 'sat_rw_b5_015', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Neither the coach nor the players ________ satisfied with the result.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'were' }, { letter: 'B', text: 'was' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer subject "players" (plural) → "were."' },
  { id: 'sat_rw_b5_016', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The company\'s new CEO________ a former engineer________ plans to restructure the organization.', question: 'Which punctuation correctly sets off the appositive?', options: [{ letter: 'A', text: ', ... ,' }, { letter: 'B', text: '; ... ;' }, { letter: 'C', text: ': ... :' }, { letter: 'D', text: '( ... )' }], correct: 'A', explanation: 'Commas set off a nonessential appositive phrase.' },
  { id: 'sat_rw_b5_017', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The team has ________ its winning streak to ten games.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'extended' }, { letter: 'B', text: 'extend' }, { letter: 'C', text: 'extending' }, { letter: 'D', text: 'extends' }], correct: 'A', explanation: '"Has extended" is present perfect tense, correct after "has."' },
  { id: 'sat_rw_b5_018', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The cake tasted ________ after being refrigerated overnight.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'good' }, { letter: 'B', text: 'well' }, { letter: 'C', text: 'goodly' }, { letter: 'D', text: 'better than' }], correct: 'A', explanation: '"Good" is an adjective that follows the linking verb "tasted" to describe the cake.' },
  { id: 'sat_rw_b5_019', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The museum was closed on Monday. We went to the park instead.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Because the museum was closed on Monday, we went to the park instead.' }, { letter: 'B', text: 'The museum was closed on Monday, we went to the park instead.' }, { letter: 'C', text: 'The museum being closed on Monday and we went to the park.' }, { letter: 'D', text: 'On Monday the museum was closed, the park was where we went.' }], correct: 'A', explanation: '"Because" establishes the causal relationship between the two events.' },
  { id: 'sat_rw_b5_020', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The committee will announce ________ decision tomorrow.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: "it's" }, { letter: 'C', text: 'their' }, { letter: 'D', text: "they're" }], correct: 'A', explanation: '"Committee" is a singular collective noun, so the possessive pronoun is "its."' },
  { id: 'sat_rw_b5_021', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The scientists who ________ the experiment published their findings in a peer-reviewed journal.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'conducted' }, { letter: 'B', text: 'conducts' }, { letter: 'C', text: 'conducting' }, { letter: 'D', text: 'has conducted' }], correct: 'A', explanation: 'Past tense "conducted" agrees with the past tense "published" later in the sentence.' },
  { id: 'sat_rw_b5_022', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The festival features musicians from various genres________ rock, jazz, hip-hop, and classical________ performing on four different stages.', question: 'Which punctuation correctly completes the text?', options: [{ letter: 'A', text: '— ... —' }, { letter: 'B', text: ', ... ,' }, { letter: 'C', text: '; ... ;' }, { letter: 'D', text: ': ... :' }], correct: 'A', explanation: 'Em dashes set off a list within a sentence where commas would cause confusion.' },
  { id: 'sat_rw_b5_023', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'If I ________ you, I would accept the job offer immediately.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'were' }, { letter: 'B', text: 'was' }, { letter: 'C', text: 'am' }, { letter: 'D', text: 'would be' }], correct: 'A', explanation: 'The subjunctive mood uses "were" for hypothetical conditions: "If I were you."' },
  { id: 'sat_rw_b5_024', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The new policy aims to reduce pollution. ________, it encourages companies to invest in renewable energy.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Additionally' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Nevertheless' }], correct: 'A', explanation: '"Additionally" adds a second related goal of the policy.' },
  { id: 'sat_rw_b5_025', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The report, which ________ over 200 pages, took six months to complete.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'spans' }, { letter: 'B', text: 'span' }, { letter: 'C', text: 'spanning' }, { letter: 'D', text: 'spanned' }], correct: 'A', explanation: '"Which" refers to "report" (singular), so "spans" is correct in the present-tense relative clause.' },
  { id: 'sat_rw_b5_026', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The author is known for her vivid prose________ her latest novel, however, has received mixed reviews.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ';' }, { letter: 'B', text: ',' }, { letter: 'C', text: ':' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A semicolon joins two independent clauses; the second begins with "however" (followed by a comma).' },
  { id: 'sat_rw_b5_027', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Each of the athletes ________ required to pass a physical exam before the season begins.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Each" is singular and requires "is."' },
  { id: 'sat_rw_b5_028', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The company launched a new product. Sales exceeded expectations in the first quarter. The board approved expansion plans.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'After the company launched a new product whose first-quarter sales exceeded expectations, the board approved expansion plans.' }, { letter: 'B', text: 'The company launched a new product, sales exceeded expectations, the board approved expansion.' }, { letter: 'C', text: 'Launching a new product and exceeding expectations, expansion plans were approved.' }, { letter: 'D', text: 'The company launched a product and the sales were good and they expanded.' }], correct: 'A', explanation: 'Option A logically sequences events with proper subordination.' },
  { id: 'sat_rw_b5_029', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Not only ________ she complete the marathon, but she also set a personal record.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'did' }, { letter: 'B', text: 'does' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'had' }], correct: 'A', explanation: '"Not only did...but also" is the correct inverted structure for past tense.' },
  { id: 'sat_rw_b5_030', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The number of applicants ________ increased steadily over the past five years.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'has' }, { letter: 'B', text: 'have' }, { letter: 'C', text: 'are' }, { letter: 'D', text: 'were' }], correct: 'A', explanation: '"The number" is singular, requiring "has."' },
  { id: 'sat_rw_b5_031', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The speakers at the conference included Dr. Amy Lee, a neuroscientist________ Prof. Mark Chen, an economist________ and Dr. Sarah Kim, a climate researcher.', question: 'Which punctuation is needed?', options: [{ letter: 'A', text: '; ... ;' }, { letter: 'B', text: ', ... ,' }, { letter: 'C', text: ': ... :' }, { letter: 'D', text: '— ... —' }], correct: 'A', explanation: 'Semicolons separate list items that contain internal commas.' },
  { id: 'sat_rw_b5_032', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'She is one of those students who ________ always prepared for class.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'are' }, { letter: 'B', text: 'is' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: '"Who" refers to "students" (plural), so "are" is correct: "students who are always prepared."' },
  { id: 'sat_rw_b5_033', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The experiment failed to produce significant results. ________, the researchers gained valuable insights about methodology.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'Nevertheless' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'Consequently' }], correct: 'A', explanation: '"Nevertheless" signals a positive outcome despite the failure.' },
  { id: 'sat_rw_b5_034', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The museum\'s collection includes paintings by artists ________ work spans three centuries.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whose' }, { letter: 'B', text: "who's" }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'whom' }], correct: 'A', explanation: '"Whose" shows possession—the work belongs to the artists.' },
  { id: 'sat_rw_b5_035', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Having studied for weeks, the exam ________ easier than expected.', question: 'What revision corrects the dangling modifier?', options: [{ letter: 'A', text: 'Having studied for weeks, she found the exam easier than expected.' }, { letter: 'B', text: 'The sentence is correct as written.' }, { letter: 'C', text: 'Having studied for weeks, it was easier than expected.' }, { letter: 'D', text: 'Studying for weeks, easier than expected was the exam.' }], correct: 'A', explanation: 'The participial phrase needs a human subject who did the studying—"she" corrects the dangling modifier.' },
  { id: 'sat_rw_b5_036', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The researchers concluded that the treatment was effective________ patients who received it showed a 40% improvement in symptoms.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces evidence supporting the conclusion.' },
  { id: 'sat_rw_b5_037', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The CEO and founder of the company ________ retiring next month.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"CEO and founder" refers to one person (who holds both titles), so "is" is correct.' },
  { id: 'sat_rw_b5_038', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The novel explores themes of identity. ________, it examines how cultural background shapes personal values.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Specifically' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"Specifically" narrows from the general (identity) to a particular aspect (cultural background).' },
  { id: 'sat_rw_b5_039', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The data from the survey ________ that consumer confidence has declined.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'indicate' }, { letter: 'B', text: 'indicates' }, { letter: 'C', text: 'indicating' }, { letter: 'D', text: 'Both A and B' }], correct: 'D', explanation: '"Data" can be treated as plural ("indicate") or singular ("indicates") in modern English.' },
  { id: 'sat_rw_b5_040', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The manager asked ________ would be responsible for training the new hires.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'who' }, { letter: 'B', text: 'whom' }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'that' }], correct: 'A', explanation: '"Who" is the subject of "would be responsible." (Whom is the object form.)' },
  { id: 'sat_rw_b5_041', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The artist\'s work was deliberately ________; she painted in a style that mimicked the apparent simplicity of children\'s drawings while embedding sophisticated compositional techniques.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'deceptive' }, { letter: 'B', text: 'primitive' }, { letter: 'C', text: 'childish' }, { letter: 'D', text: 'amateur' }], correct: 'A', explanation: 'Deceptive (misleading in appearance) fits—the apparent simplicity hides sophistication.' },
  { id: 'sat_rw_b5_042', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The diplomat\'s proposal served as a ________ between the two warring factions, offering concessions that both sides could accept.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'compromise' }, { letter: 'B', text: 'surrender' }, { letter: 'C', text: 'victory' }, { letter: 'D', text: 'ultimatum' }], correct: 'A', explanation: 'Compromise (mutual concessions) fits the description of acceptable concessions for both sides.' },
  { id: 'sat_rw_b5_043', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The wildlife biologist observed that the species was remarkably ________, thriving in environments ranging from dense forests to open grasslands.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'adaptable' }, { letter: 'B', text: 'fragile' }, { letter: 'C', text: 'selective' }, { letter: 'D', text: 'specialized' }], correct: 'A', explanation: 'Adaptable (able to adjust to various conditions) matches thriving in diverse environments.' },
  { id: 'sat_rw_b5_044', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The Industrial Revolution transformed not only manufacturing but also social structures. As factories replaced cottage industries, workers migrated from rural areas to cities, creating unprecedented urban density. This shift disrupted traditional family structures, as both men and women increasingly worked outside the home. While wages were often low and conditions harsh, the era also laid the groundwork for organized labor movements.', question: 'According to the passage, which was a social consequence of the Industrial Revolution?', options: [{ letter: 'A', text: 'Traditional family structures were disrupted by factory work' }, { letter: 'B', text: 'Cottage industries became more profitable' }, { letter: 'C', text: 'Workers remained in rural areas' }, { letter: 'D', text: 'Wages increased dramatically for all workers' }], correct: 'A', explanation: 'The passage directly states the shift "disrupted traditional family structures."' },
  { id: 'sat_rw_b5_045', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The professor\'s ________ manner put students at ease; she was approachable and always willing to explain concepts multiple times.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'affable' }, { letter: 'B', text: 'austere' }, { letter: 'C', text: 'intimidating' }, { letter: 'D', text: 'aloof' }], correct: 'A', explanation: 'Affable (friendly, good-natured) matches putting students at ease and being approachable.' },
  { id: 'sat_rw_b5_046', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Barely ________ the announcement been made when the crowd erupted in cheers.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'had' }, { letter: 'B', text: 'has' }, { letter: 'C', text: 'did' }, { letter: 'D', text: 'was' }], correct: 'A', explanation: '"Barely had...when" is the correct inverted past perfect structure.' },
  { id: 'sat_rw_b5_047', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The coach emphasized one quality above all others________ resilience.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'D', explanation: 'An em dash creates dramatic emphasis before revealing the single quality.' },
  { id: 'sat_rw_b5_048', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'It is essential that every employee ________ the safety training before starting work.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'complete' }, { letter: 'B', text: 'completes' }, { letter: 'C', text: 'completed' }, { letter: 'D', text: 'will complete' }], correct: 'A', explanation: 'The subjunctive mood after "essential that" uses the base form: "complete."' },
  { id: 'sat_rw_b5_049', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'Exercise improves physical health. It also boosts mental well-being. Many doctors recommend at least 30 minutes of daily activity.', question: 'Which choice best combines these ideas?', options: [{ letter: 'A', text: 'Because exercise improves both physical health and mental well-being, many doctors recommend at least 30 minutes of daily activity.' }, { letter: 'B', text: 'Exercise improves health and well-being, doctors recommend 30 minutes daily.' }, { letter: 'C', text: 'Physical health and mental well-being are improved by exercise, which is why 30 minutes.' }, { letter: 'D', text: 'Exercise is good and doctors say 30 minutes of it daily.' }], correct: 'A', explanation: 'Option A logically links the benefits (cause) to the recommendation (effect).' },
  { id: 'sat_rw_b5_050', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The evidence ________ to a conclusion that contradicts the original hypothesis.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'points' }, { letter: 'B', text: 'point' }, { letter: 'C', text: 'pointing' }, { letter: 'D', text: 'have pointed' }], correct: 'A', explanation: '"Evidence" is singular (uncountable noun), requiring "points."' },
  { id: 'sat_rw_b5_051', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The professor, along with several graduate students, ________ presenting at the international conference next week.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: '"Along with" is parenthetical; the subject is "professor" (singular), requiring "is."' },
  { id: 'sat_rw_b5_052', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The researchers identified three key variables________ temperature, which affected reaction speed; humidity, which influenced crystal formation; and pressure, which determined yield.', question: 'Which punctuation completes the text?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: '—' }, { letter: 'C', text: ',' }, { letter: 'D', text: 'Both A and B' }], correct: 'D', explanation: 'Both a colon and em dash can introduce a list, especially when the list uses semicolons.' },
  { id: 'sat_rw_b5_053', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Had the committee ________ earlier, the project might have stayed on schedule.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'acted' }, { letter: 'B', text: 'acting' }, { letter: 'C', text: 'act' }, { letter: 'D', text: 'acts' }], correct: 'A', explanation: 'Inverted conditional: "Had the committee acted" = "If the committee had acted."' },
  { id: 'sat_rw_b5_054', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The archaeological evidence supports the theory. However, some historians question the dating methodology. Others argue the samples may have been contaminated.', question: 'Which choice best combines the second and third sentences?', options: [{ letter: 'A', text: 'However, some historians question the dating methodology, while others argue the samples may have been contaminated.' }, { letter: 'B', text: 'However, the dating methodology is questioned and the samples may be contaminated.' }, { letter: 'C', text: 'However, some historians and others question and argue about the methodology and samples.' }, { letter: 'D', text: 'However, questioning the dating methodology, the samples were argued to be contaminated.' }], correct: 'A', explanation: '"While" effectively contrasts the two different objections.' },
  { id: 'sat_rw_b5_055', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The artist to ________ the prize was awarded has declined to attend the ceremony.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whom' }, { letter: 'B', text: 'who' }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'that' }], correct: 'A', explanation: '"Whom" is the object of the preposition "to": the prize was awarded to whom.' },
  { id: 'sat_rw_b5_056', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The study\'s findings were clear________ participants who exercised regularly reported higher levels of life satisfaction than those who did not.', question: 'Which punctuation completes the text?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the specific finding that explains the general statement.' },
  { id: 'sat_rw_b5_057', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The diversity of opinions expressed during the meeting ________ the board\'s decision-making process more robust.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'made' }, { letter: 'B', text: 'make' }, { letter: 'C', text: 'making' }, { letter: 'D', text: 'have made' }], correct: 'A', explanation: '"Diversity" is singular, and the sentence is past tense, requiring "made."' },
  { id: 'sat_rw_b5_058', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The proposed legislation has several benefits. Opponents argue it would be too costly. The bill is currently stalled in committee.', question: 'Which revision best connects these ideas?', options: [{ letter: 'A', text: 'Although the proposed legislation has several benefits, opponents argue it would be too costly, and the bill is currently stalled in committee.' }, { letter: 'B', text: 'The legislation has benefits but opponents say costly and stalled in committee.' }, { letter: 'C', text: 'Having several benefits, the legislation is opposed for being costly, stalling.' }, { letter: 'D', text: 'The proposed legislation, which has benefits, opponents argue is costly, stalled in committee.' }], correct: 'A', explanation: 'Option A uses "although" for concession and "and" to add the current status.' },
  { id: 'sat_rw_b5_059', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The research team, each of ________ members contributed unique expertise, produced a comprehensive report.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whose' }, { letter: 'B', text: "who's" }, { letter: 'C', text: 'which' }, { letter: 'D', text: 'whom' }], correct: 'A', explanation: '"Whose" shows possession—the members belong to the team.' },
  { id: 'sat_rw_b5_060', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Were the evidence ________ sufficient, the case would have been resolved months ago.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'deemed' }, { letter: 'B', text: 'deeming' }, { letter: 'C', text: 'deems' }, { letter: 'D', text: 'to deem' }], correct: 'A', explanation: 'Inverted subjunctive: "Were the evidence deemed sufficient" = "If the evidence had been deemed sufficient."' },
  { id: 'sat_rw_b5_061', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The new employee quickly proved herself to be ________; she learned procedures faster than any of her predecessors.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'adept' }, { letter: 'B', text: 'inept' }, { letter: 'C', text: 'reluctant' }, { letter: 'D', text: 'complacent' }], correct: 'A', explanation: 'Adept (very skilled or proficient) matches learning faster than predecessors.' },
  { id: 'sat_rw_b5_062', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The instructions were so ________ that even a child could follow them without difficulty.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'straightforward' }, { letter: 'B', text: 'convoluted' }, { letter: 'C', text: 'obscure' }, { letter: 'D', text: 'perplexing' }], correct: 'A', explanation: 'Straightforward (easy to understand) matches instructions a child could follow.' },
  { id: 'sat_rw_b5_063', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'After weeks of drought, the farmers welcomed the ________ rain that finally arrived.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'long-awaited' }, { letter: 'B', text: 'unwelcome' }, { letter: 'C', text: 'destructive' }, { letter: 'D', text: 'insignificant' }], correct: 'A', explanation: 'Long-awaited matches the context of welcoming rain after weeks of drought.' },
  { id: 'sat_rw_b5_064', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Dolphins are among the most intelligent marine mammals. They communicate using a complex system of clicks, whistles, and body movements. Each dolphin develops its own unique whistle, called a "signature whistle," which functions much like a name, allowing other dolphins to identify and call specific individuals.', question: 'A "signature whistle" is best described as:', options: [{ letter: 'A', text: 'A unique sound that serves as an individual identifier for each dolphin' }, { letter: 'B', text: 'A warning signal used to alert the group to danger' }, { letter: 'C', text: 'A sound all dolphins make when they are happy' }, { letter: 'D', text: 'A mating call unique to male dolphins' }], correct: 'A', explanation: 'The passage states it "functions much like a name, allowing other dolphins to identify and call specific individuals."' },
  { id: 'sat_rw_b5_065', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The company\'s decision to expand overseas was considered ________; with limited capital, many felt the risks outweighed potential gains.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'reckless' }, { letter: 'B', text: 'prudent' }, { letter: 'C', text: 'conservative' }, { letter: 'D', text: 'cautious' }], correct: 'A', explanation: 'Reckless (without thought of danger) fits the criticism that risks outweighed gains with limited capital.' },
  { id: 'sat_rw_b5_066', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The author\'s analysis of the economic crisis was praised for its ________; rather than seeking easy scapegoats, she traced the collapse to a complex interplay of regulatory failures, market psychology, and institutional incentives.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'rigor' }, { letter: 'B', text: 'brevity' }, { letter: 'C', text: 'partiality' }, { letter: 'D', text: 'levity' }], correct: 'A', explanation: 'Rigor (thoroughness, careful analysis) matches the detailed, multifaceted analysis described.' },
  { id: 'sat_rw_b5_067', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The politician\'s rhetoric was ________; his speeches used patriotic imagery and emotional appeals to mask proposals that would primarily benefit wealthy donors.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'disingenuous' }, { letter: 'B', text: 'transparent' }, { letter: 'C', text: 'forthcoming' }, { letter: 'D', text: 'sincere' }], correct: 'A', explanation: 'Disingenuous (not candid, giving a false appearance) matches using appeals to mask self-serving proposals.' },
  { id: 'sat_rw_b5_068', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The trolley problem, a thought experiment in ethics, asks whether it is morally acceptable to divert a runaway trolley from a track where it will kill five people to one where it will kill one person. Most people say yes. But in a variant where saving the five requires physically pushing a bystander in front of the trolley, most say no—even though the outcome is identical. This suggests that moral judgments are influenced not only by consequences but also by the means used to achieve them.', question: 'The trolley problem variants together suggest that:', options: [{ letter: 'A', text: 'People distinguish morally between actions based on how directly involved they are in causing harm' }, { letter: 'B', text: 'People always prioritize saving the greatest number of lives' }, { letter: 'C', text: 'Moral reasoning is purely based on calculating outcomes' }, { letter: 'D', text: 'Most people refuse to make any moral decisions under pressure' }], correct: 'A', explanation: 'The passage shows people accept diverting the trolley but not physically pushing someone—the directness of involvement matters.' },
  { id: 'sat_rw_b5_069', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The composer\'s late symphonies are characterized by a ________ complexity: layers of melody, rhythm, and harmony interweave to create an effect that seems simultaneously ordered and chaotic.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'labyrinthine' }, { letter: 'B', text: 'rudimentary' }, { letter: 'C', text: 'transparent' }, { letter: 'D', text: 'pedestrian' }], correct: 'A', explanation: 'Labyrinthine (intricate, maze-like) matches the description of interwoven layers seeming both ordered and chaotic.' },
  { id: 'sat_rw_b5_070', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The replication crisis in psychology refers to the finding that many published studies cannot be reproduced when other researchers attempt to repeat them. A 2015 effort to replicate 100 psychology studies found that only 36% produced results consistent with the originals. Critics blame publication bias—journals\' preference for novel, positive results—and questionable research practices such as p-hacking, where researchers selectively analyze data until they find statistically significant results.', question: 'Based on the passage, "p-hacking" contributes to the replication crisis by:', options: [{ letter: 'A', text: 'Producing statistically significant results that may not reflect genuine effects' }, { letter: 'B', text: 'Making experiments too expensive to replicate' }, { letter: 'C', text: 'Preventing other researchers from accessing the original data' }, { letter: 'D', text: 'Requiring overly large sample sizes' }], correct: 'A', explanation: 'P-hacking involves selectively analyzing data to find significant results, which may not represent real effects and thus fail replication.' },
  { id: 'sat_rw_b5_071', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The government announced a new infrastructure plan. It includes funding for bridges, roads, and public transit. ________, the plan allocates resources for broadband expansion in rural areas.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Moreover' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'Conversely' }, { letter: 'D', text: 'Instead' }], correct: 'A', explanation: '"Moreover" adds another element to the infrastructure plan.' },
  { id: 'sat_rw_b5_072', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The phenomenon, ________ scientists had studied for decades, was finally explained by the new theory.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'which' }, { letter: 'B', text: 'that' }, { letter: 'C', text: 'whom' }, { letter: 'D', text: 'whose' }], correct: 'A', explanation: '"Which" introduces a nonessential relative clause referring to "phenomenon."' },
  { id: 'sat_rw_b5_073', category: 'writing', subcategory: 'punctuation', difficulty: 'hard', passage: 'The author acknowledges several limitations________ the small sample size, the short duration of the study, and the lack of a control group________ but argues that the results are still meaningful.', question: 'Which punctuation is correct?', options: [{ letter: 'A', text: '— ... —' }, { letter: 'B', text: ', ... ,' }, { letter: 'C', text: '; ... ;' }, { letter: 'D', text: ': ... :' }], correct: 'A', explanation: 'Em dashes set off a list within a sentence, especially when the list contains commas.' },
  { id: 'sat_rw_b5_074', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Neither the analysis of the economic data nor the review of historical precedents ________ a clear answer to the question.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'provides' }, { letter: 'B', text: 'provide' }, { letter: 'C', text: 'are providing' }, { letter: 'D', text: 'have provided' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer subject "review" (singular), so "provides."' },
  { id: 'sat_rw_b5_075', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The study found a strong correlation between sleep quality and academic performance. Students who slept 7-9 hours consistently earned higher grades. ________, this correlation does not prove causation, as other factors may be involved.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Importantly' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Therefore' }, { letter: 'D', text: 'Furthermore' }], correct: 'A', explanation: '"Importantly" introduces a crucial caveat about correlation vs. causation.' },
  { id: 'sat_rw_b5_076', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The CEO\'s decision to merge with a competitor was ________—a bold gamble that could either double the company\'s market share or lead to its dissolution.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'audacious' }, { letter: 'B', text: 'timid' }, { letter: 'C', text: 'conventional' }, { letter: 'D', text: 'trivial' }], correct: 'A', explanation: 'Audacious (bold, daring) matches "bold gamble" with extreme potential outcomes.' },
  { id: 'sat_rw_b5_077', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The jury, after deliberating for three days, ________ reached a unanimous verdict.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'finally' }, { letter: 'B', text: 'final' }, { letter: 'C', text: 'finalize' }, { letter: 'D', text: 'finality' }], correct: 'A', explanation: '"Finally" is an adverb modifying the verb "reached."' },
  { id: 'sat_rw_b5_078', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Confirmation bias—the tendency to seek, interpret, and remember information that confirms pre-existing beliefs—affects even trained scientists. In a famous demonstration, researchers asked subjects to evaluate the methodological quality of studies on capital punishment. Subjects consistently rated studies that supported their existing views as more rigorous than those that contradicted them, regardless of the actual quality. This finding suggests that mere exposure to evidence does not guarantee objectivity.', question: 'The study described demonstrates that:', options: [{ letter: 'A', text: 'People evaluate evidence quality based partly on whether it aligns with their beliefs' }, { letter: 'B', text: 'Studies on capital punishment are inherently low quality' }, { letter: 'C', text: 'Scientists are immune to confirmation bias' }, { letter: 'D', text: 'Presenting contradictory evidence always changes minds' }], correct: 'A', explanation: 'Subjects rated studies supporting their views as better, "regardless of the actual quality."' },
  { id: 'sat_rw_b5_079', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'It is the researchers, not the funding agency, who ________ responsible for the accuracy of the data.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'are' }, { letter: 'B', text: 'is' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: '"Who" refers to "researchers" (plural), so "are" is correct.' },
  { id: 'sat_rw_b5_080', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The building was designed to withstand earthquakes. ________, it incorporates a base isolation system that allows the structure to move independently of ground motion.', question: 'Which transition best connects these sentences?', options: [{ letter: 'A', text: 'To this end' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Nevertheless' }, { letter: 'D', text: 'Similarly' }], correct: 'A', explanation: '"To this end" connects the purpose (earthquake resistance) with the means (base isolation).' },
  { id: 'sat_rw_b5_081', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The child\'s ________ for sweets was evident; she always chose candy over fruit when given the option.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'preference' }, { letter: 'B', text: 'aversion' }, { letter: 'C', text: 'indifference' }, { letter: 'D', text: 'antipathy' }], correct: 'A', explanation: 'Preference (a greater liking for one thing) matches always choosing candy over fruit.' },
  { id: 'sat_rw_b5_082', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The storm caused ________ damage to the coastal town, destroying homes and flooding streets.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'extensive' }, { letter: 'B', text: 'minimal' }, { letter: 'C', text: 'negligible' }, { letter: 'D', text: 'moderate' }], correct: 'A', explanation: 'Extensive (covering a large area) matches the description of destroyed homes and flooded streets.' },
  { id: 'sat_rw_b5_083', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Photosynthesis is the process by which green plants convert sunlight, water, and carbon dioxide into glucose and oxygen. This process occurs primarily in the leaves, where chlorophyll—the green pigment—absorbs light energy. Without photosynthesis, life as we know it would not exist, as it produces both the food that sustains plant growth and the oxygen that most organisms need to survive.', question: 'According to the passage, chlorophyll\'s role in photosynthesis is to:', options: [{ letter: 'A', text: 'Absorb light energy needed for the process' }, { letter: 'B', text: 'Convert carbon dioxide into oxygen' }, { letter: 'C', text: 'Transport water from roots to leaves' }, { letter: 'D', text: 'Store glucose for later use' }], correct: 'A', explanation: 'The passage states chlorophyll "absorbs light energy."' },
  { id: 'sat_rw_b5_084', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The documentary filmmakers adopted an ________ approach, presenting multiple perspectives on the controversial issue without advocating for any particular position.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'impartial' }, { letter: 'B', text: 'partisan' }, { letter: 'C', text: 'dogmatic' }, { letter: 'D', text: 'biased' }], correct: 'A', explanation: 'Impartial (treating all sides equally) matches presenting multiple perspectives without advocacy.' },
  { id: 'sat_rw_b5_085', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The therapist noted that the patient\'s recovery had ________, with no significant improvement in the past three months.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'stagnated' }, { letter: 'B', text: 'accelerated' }, { letter: 'C', text: 'flourished' }, { letter: 'D', text: 'progressed' }], correct: 'A', explanation: 'Stagnated (ceased to develop or progress) matches "no significant improvement."' },
  { id: 'sat_rw_b5_086', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The anchoring effect is a cognitive bias in which people rely too heavily on the first piece of information they encounter when making decisions. In negotiations, for example, the first number mentioned tends to serve as an anchor that influences all subsequent offers. Even when participants are told the anchor is arbitrary, studies show it still affects their estimates. This suggests the anchoring effect operates at a subconscious level.', question: 'The passage suggests that the anchoring effect is particularly powerful because:', options: [{ letter: 'A', text: 'It influences decisions even when people know the anchor is arbitrary' }, { letter: 'B', text: 'It only affects people who are inexperienced negotiators' }, { letter: 'C', text: 'It can be easily overcome through training' }, { letter: 'D', text: 'It only occurs in formal negotiation settings' }], correct: 'A', explanation: 'The passage states the effect persists "even when participants are told the anchor is arbitrary."' },
  { id: 'sat_rw_b5_087', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The geologist\'s findings were ________ by independent researchers who conducted their own analysis and reached the same conclusions.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'corroborated' }, { letter: 'B', text: 'refuted' }, { letter: 'C', text: 'challenged' }, { letter: 'D', text: 'dismissed' }], correct: 'A', explanation: 'Corroborated (confirmed by additional evidence) matches independent researchers reaching the same conclusions.' },
  { id: 'sat_rw_b5_088', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The critic argued that the novel\'s ending was ________—after 400 pages of psychological complexity, the characters\' conflicts were resolved through a series of improbable coincidences.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'anticlimactic' }, { letter: 'B', text: 'riveting' }, { letter: 'C', text: 'profound' }, { letter: 'D', text: 'satisfying' }], correct: 'A', explanation: 'Anticlimactic (a disappointing end to something exciting) matches improbable coincidences after 400 pages of complexity.' },
  { id: 'sat_rw_b5_089', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The Jevons paradox, first described in 1865, observes that technological improvements in resource efficiency can paradoxically lead to increased, rather than decreased, total resource consumption. When coal-burning engines became more efficient, coal use did not decline—it soared, because cheaper energy made coal viable for more applications. Modern economists see echoes of this paradox in fuel efficiency standards: as cars become more efficient, driving becomes cheaper, encouraging people to drive more.', question: 'The Jevons paradox suggests that efficiency improvements may fail to conserve resources because:', options: [{ letter: 'A', text: 'Lower costs per unit encourage greater total usage' }, { letter: 'B', text: 'Technology inevitably becomes less efficient over time' }, { letter: 'C', text: 'People deliberately waste resources when they become cheaper' }, { letter: 'D', text: 'Governments always increase resource extraction rates' }], correct: 'A', explanation: 'The paradox shows that efficiency reduces per-unit cost, expanding usage to more applications and increasing total consumption.' },
  { id: 'sat_rw_b5_090', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The historian\'s account was deliberately ________; she acknowledged the limitations of her sources and the gaps in the historical record rather than presenting her interpretation as definitive truth.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'circumspect' }, { letter: 'B', text: 'dogmatic' }, { letter: 'C', text: 'authoritative' }, { letter: 'D', text: 'reckless' }], correct: 'A', explanation: 'Circumspect (wary, careful to consider all circumstances) matches acknowledging limitations rather than claiming definitiveness.' },
  { id: 'sat_rw_b5_091', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The dog wagged ________ tail excitedly when the owner returned home.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: "it's" }, { letter: 'C', text: 'their' }, { letter: 'D', text: "there" }], correct: 'A', explanation: '"Its" is the possessive form for "dog."' },
  { id: 'sat_rw_b5_092', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The athlete performed ________ well at the competition, earning three gold medals.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'exceptionally' }, { letter: 'B', text: 'exceptional' }, { letter: 'C', text: 'exception' }, { letter: 'D', text: 'excepted' }], correct: 'A', explanation: 'The adverb "exceptionally" modifies the adverb "well."' },
  { id: 'sat_rw_b5_093', category: 'writing', subcategory: 'punctuation', difficulty: 'easy', passage: 'The teacher\'s feedback was encouraging________ "Your essay shows real improvement in argument structure."', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces the direct quote that exemplifies the encouraging feedback.' },
  { id: 'sat_rw_b5_094', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The two brothers look so much ________ that people often mistake them for twins.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'alike' }, { letter: 'B', text: 'likely' }, { letter: 'C', text: 'like' }, { letter: 'D', text: 'likely to' }], correct: 'A', explanation: '"Alike" means similar in appearance, fitting the context of being mistaken for twins.' },
  { id: 'sat_rw_b5_095', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'She studied hard. She passed the exam with flying colors.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Having studied hard, she passed the exam with flying colors.' }, { letter: 'B', text: 'She studied hard, she passed the exam with flying colors.' }, { letter: 'C', text: 'Studying hard and passing the exam with flying colors.' }, { letter: 'D', text: 'Hard studying, the exam was passed with flying colors.' }], correct: 'A', explanation: 'The participial phrase "Having studied hard" connects cause to effect.' },
  { id: 'sat_rw_b5_096', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'A number of students ________ already signed up for the trip.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'have' }, { letter: 'B', text: 'has' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'was' }], correct: 'A', explanation: '"A number of" is plural (unlike "the number of"), requiring "have."' },
  { id: 'sat_rw_b5_097', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The CEO issued a brief statement________ "We are committed to transparency and will cooperate fully with the investigation."', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ':' }, { letter: 'B', text: ',' }, { letter: 'C', text: ';' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A colon introduces a direct quote after a complete sentence.' },
  { id: 'sat_rw_b5_098', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The theory, ________ has been debated for decades, may finally be resolved by the new experimental data.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'which' }, { letter: 'B', text: 'that' }, { letter: 'C', text: 'who' }, { letter: 'D', text: 'whom' }], correct: 'A', explanation: '"Which" introduces a nonessential relative clause about the theory (a thing).' },
  { id: 'sat_rw_b5_099', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'Many cities face water shortages. Some have implemented rainwater harvesting systems. ________, others have turned to desalination as a solution.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Meanwhile' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'However' }, { letter: 'D', text: 'As a result' }], correct: 'A', explanation: '"Meanwhile" presents a parallel approach taken by different cities.' },
  { id: 'sat_rw_b5_100', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The species of bird that ________ in this region are threatened by habitat loss.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'nest' }, { letter: 'B', text: 'nests' }, { letter: 'C', text: 'nesting' }, { letter: 'D', text: 'has nested' }], correct: 'A', explanation: '"Species" here is plural (multiple species), and "that" refers to "species," so "nest" is correct.' },
  { id: 'sat_rw_b5_101', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The speaker\'s ________ tone made the audience feel comfortable and engaged throughout the presentation.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'conversational' }, { letter: 'B', text: 'hostile' }, { letter: 'C', text: 'monotonous' }, { letter: 'D', text: 'condescending' }], correct: 'A', explanation: 'Conversational (informal, relaxed) matches making the audience comfortable and engaged.' },
  { id: 'sat_rw_b5_102', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The new building was designed to be environmentally ________; it uses solar panels and recycled materials throughout.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'sustainable' }, { letter: 'B', text: 'wasteful' }, { letter: 'C', text: 'conventional' }, { letter: 'D', text: 'temporary' }], correct: 'A', explanation: 'Sustainable (able to be maintained without depleting resources) matches solar panels and recycled materials.' },
  { id: 'sat_rw_b5_103', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The merger between the two companies was ________; both sides benefited from shared resources and expanded market reach.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'mutually beneficial' }, { letter: 'B', text: 'one-sided' }, { letter: 'C', text: 'detrimental' }, { letter: 'D', text: 'contentious' }], correct: 'A', explanation: 'Mutually beneficial matches both sides benefiting.' },
  { id: 'sat_rw_b5_104', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The musician\'s performance was ________; the audience sat in stunned silence for several seconds after the final note before erupting in applause.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'mesmerizing' }, { letter: 'B', text: 'mediocre' }, { letter: 'C', text: 'tedious' }, { letter: 'D', text: 'forgettable' }], correct: 'A', explanation: 'Mesmerizing (captivating, spellbinding) matches stunned silence followed by enthusiastic applause.' },
  { id: 'sat_rw_b5_105', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The broken windows theory suggests that visible signs of disorder—such as vandalism, litter, or broken windows—encourage further crime and antisocial behavior. The theory proposes that when minor infractions go unaddressed, they signal that an area is unmonitored, emboldening more serious criminal activity. While some cities have implemented policing strategies based on this theory, critics argue that these approaches can lead to over-policing of minor offenses and disproportionately affect marginalized communities.', question: 'The critics mentioned in the passage would most likely support:', options: [{ letter: 'A', text: 'Policing strategies that address root causes of crime rather than minor infractions' }, { letter: 'B', text: 'Stricter enforcement of all minor offenses' }, { letter: 'C', text: 'Removing all policing from urban areas' }, { letter: 'D', text: 'Implementing broken windows policing in every city' }], correct: 'A', explanation: 'Critics worry about over-policing minor offenses and disproportionate effects, suggesting they would prefer addressing root causes.' },
  { id: 'sat_rw_b5_106', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The architect\'s design was deliberately ________; the building\'s stark geometric forms and exposed concrete surfaces rejected the decorative excess of previous styles.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'minimalist' }, { letter: 'B', text: 'ornate' }, { letter: 'C', text: 'eclectic' }, { letter: 'D', text: 'flamboyant' }], correct: 'A', explanation: 'Minimalist (using the fewest elements) matches stark forms and rejection of decorative excess.' },
  { id: 'sat_rw_b5_107', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The collection of rare manuscripts, ________ value has been estimated at over ten million dollars, is housed in a climate-controlled vault.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'whose' }, { letter: 'B', text: "who's" }, { letter: 'C', text: 'which' }, { letter: 'D', text: "it's" }], correct: 'A', explanation: '"Whose" shows possession (the value belongs to the collection).' },
  { id: 'sat_rw_b5_108', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The pharmaceutical company invested heavily in research. Clinical trials showed promising results for the new drug. ________, the FDA required additional safety data before granting approval.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Despite this' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'As a result' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"Despite this" signals that the FDA\'s requirement came despite the promising results.' },
  { id: 'sat_rw_b5_109', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The prisoner\'s dilemma, a foundational concept in game theory, demonstrates why two rational individuals might not cooperate even when it would be in their mutual interest. Each player faces a choice: cooperate or betray. If both cooperate, both benefit moderately. If one betrays while the other cooperates, the betrayer gains significantly while the cooperator suffers. If both betray, both suffer, but less than the cooperator in the mixed scenario. Rational self-interest drives both players to betray, resulting in a worse outcome than mutual cooperation.', question: 'The prisoner\'s dilemma illustrates that:', options: [{ letter: 'A', text: 'Individually rational decisions can lead to collectively suboptimal outcomes' }, { letter: 'B', text: 'Cooperation is always the best individual strategy' }, { letter: 'C', text: 'Betrayal always produces the worst outcome for the betrayer' }, { letter: 'D', text: 'Rational people always find the optimal solution' }], correct: 'A', explanation: 'The passage shows that rational self-interest (betrayal) produces worse outcomes than cooperation, illustrating individual rationality leading to collective irrationality.' },
  { id: 'sat_rw_b5_110', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'So compelling ________ the evidence that even the most skeptical committee members voted to approve the project.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'was' }, { letter: 'B', text: 'were' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'being' }], correct: 'A', explanation: 'Inverted sentence: "So compelling was the evidence" = "The evidence was so compelling."' },
  { id: 'sat_rw_b5_111', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The garden was in a state of ________; weeds had overtaken the flower beds and the fence was falling apart.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'neglect' }, { letter: 'B', text: 'bloom' }, { letter: 'C', text: 'renovation' }, { letter: 'D', text: 'splendor' }], correct: 'A', explanation: 'Neglect (lack of care) matches weeds overtaking beds and a falling fence.' },
  { id: 'sat_rw_b5_112', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The scientist was known for her ________ approach to research, often spending months planning an experiment before conducting a single trial.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'methodical' }, { letter: 'B', text: 'impulsive' }, { letter: 'C', text: 'reckless' }, { letter: 'D', text: 'spontaneous' }], correct: 'A', explanation: 'Methodical (systematic, orderly) matches spending months planning before experimenting.' },
  { id: 'sat_rw_b5_113', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The students were asked to compare the works of Shakespeare ________ those of Marlowe.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'with' }, { letter: 'B', text: 'to' }, { letter: 'C', text: 'against' }, { letter: 'D', text: 'Both A and B' }], correct: 'D', explanation: '"Compare with" and "compare to" are both acceptable, though with slightly different nuances.' },
  { id: 'sat_rw_b5_114', category: 'writing', subcategory: 'punctuation', difficulty: 'medium', passage: 'The restaurant received excellent reviews________ however, it closed within a year due to rising rent costs.', question: 'Which punctuation completes the text correctly?', options: [{ letter: 'A', text: ';' }, { letter: 'B', text: ',' }, { letter: 'C', text: ':' }, { letter: 'D', text: '—' }], correct: 'A', explanation: 'A semicolon correctly precedes "however" between two independent clauses.' },
  { id: 'sat_rw_b5_115', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The anthropologist\'s fieldwork revealed that the community\'s traditions were far from ________—what appeared to outsiders as unchanging customs were actually dynamic practices that had evolved significantly over generations.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'static' }, { letter: 'B', text: 'evolving' }, { letter: 'C', text: 'vibrant' }, { letter: 'D', text: 'flexible' }], correct: 'A', explanation: 'Static (unchanging) creates the needed contrast—the traditions appeared static but were actually dynamic.' },
  { id: 'sat_rw_b5_116', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The evidence, as well as the testimony of several witnesses, ________ the prosecution\'s case.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'supports' }, { letter: 'B', text: 'support' }, { letter: 'C', text: 'are supporting' }, { letter: 'D', text: 'have supported' }], correct: 'A', explanation: '"As well as" is parenthetical; the subject is "evidence" (singular), requiring "supports."' },
  { id: 'sat_rw_b5_117', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The policy was intended to reduce inequality. Instead, it widened the gap between rich and poor. ________, the government revised its approach.', question: 'Which transition best connects these ideas?', options: [{ letter: 'A', text: 'Consequently' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Furthermore' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"Consequently" shows the government revised its approach as a result of the unintended outcome.' },
  { id: 'sat_rw_b5_118', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The author\'s argument was ultimately ________; while it raised interesting questions, it failed to provide convincing evidence for its central claim.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'unconvincing' }, { letter: 'B', text: 'definitive' }, { letter: 'C', text: 'revolutionary' }, { letter: 'D', text: 'conclusive' }], correct: 'A', explanation: 'Unconvincing matches failing to provide convincing evidence.' },
  { id: 'sat_rw_b5_119', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'Either the manager or the supervisors ________ expected to attend the meeting.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'are' }, { letter: 'B', text: 'is' }, { letter: 'C', text: 'was' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: 'With "either...or," the verb agrees with the nearer subject "supervisors" (plural) → "are."' },
  { id: 'sat_rw_b5_120', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The Hawthorne effect refers to the alteration of behavior by subjects of a study due to their awareness of being observed. Named after experiments at the Western Electric Hawthorne Works in the 1920s, the effect suggests that any change in working conditions—whether an improvement or not—can temporarily increase productivity simply because workers know they are being studied. This poses a significant methodological challenge for researchers across disciplines, as it means observed behavior may not accurately reflect typical behavior.', question: 'The Hawthorne effect is problematic for researchers because it:', options: [{ letter: 'A', text: 'Makes it difficult to distinguish genuine effects from reactions to being observed' }, { letter: 'B', text: 'Only occurs in industrial settings' }, { letter: 'C', text: 'Always increases the accuracy of study results' }, { letter: 'D', text: 'Can be easily eliminated through proper study design' }], correct: 'A', explanation: 'The passage states "observed behavior may not accurately reflect typical behavior," making it hard to know if results reflect the intervention or just the observation.' }
];
